import React, { useState, useCallback, useMemo } from 'react';
import { useInAppNavigate } from '../../../router/useInAppNavigate';

import {
  Select,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
} from '@linm-soft-org/linm-web-common-components';
import { DocumentProcessingLevelPill } from '../../../components/document/DocumentProcessingLevelPill';
import {
  COST_SHEET_LEVEL_FILTER_OPTIONS,
  formatCostSheetProcessingLevel,
} from '../../../utils/documentProcessingLevelDisplay';
import { useAppDispatch } from '../../../store/hooks';
import { gtService } from '../../../services/gt/gtService';
import type { CostSheetDto, WipBalanceDto } from '../../../services/gt/models';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { giaThanhPageLabels as L } from '../../../constants/giaThanhPageLabels';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { useCostSheetPermissions } from '../../../hooks/useCostSheetPermissions';
import erp from '../../../styles/erpPage.module.css';
import { useVoucherListTableBusy } from '../../../components/list/useVoucherListTableBusy';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';

const TEST_ID = 'erp-gia-thanh';
const PAGE_ID = 'gt-gia-thanh';
const PAGE_SIZE = DEFAULT_PAGE_SIZE;

const PROCESSING_LEVEL_OPTIONS = COST_SHEET_LEVEL_FILTER_OPTIONS;

const GiaThanhListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useInAppNavigate();
  const { canRead } = useCostSheetPermissions();
  const now = new Date();
  const [month, setMonth] = useState(String(now.getMonth() + 1));
  const [year, setYear] = useState(String(now.getFullYear()));
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState<ListPageSize>(PAGE_SIZE);
  const [processingLevel, setProcessingLevel] = useState('');
  const [items, setItems] = useState<CostSheetDto[]>([]);
  const [wipRows, setWipRows] = useState<WipBalanceDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);

  const { showTableLoading } = useVoucherListTableBusy(loading);

  const handleLoad = useCallback(() => {
    if (!canRead) {
      setItems([]);
      setWipRows([]);
      setTotalCount(0);
      setLoading(false);
      return;
    }
    setLoading(true);
    Promise.all([
      gtService.getCostSheets({
        month: Number(month),
        year: Number(year),
        processingLevel: processingLevel || undefined,
        page,
        pageSize,
      }),
      gtService.getWipBalance(Number(month), Number(year)),
    ])
      .then(([res, wip]) => {
        setItems(res.items);
        setTotalCount(res.totalCount);
        setWipRows(wip);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, L.list.loadError),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [canRead, month, year, processingLevel, page, pageSize, dispatch]);

  const refresh = useCallback(() => {
    handleLoad();
  }, [handleLoad]);

  const wipOpening = wipRows.reduce((sum, row) => sum + row.openingAmount, 0);
  const wipClosing = wipRows.reduce((sum, row) => sum + row.closingAmount, 0);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      if (!cancelled) handleLoad();
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [handleLoad]);

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canChart: false,
      canPrint: false,
    }),
    [refresh],
  );

  const fromDate = `${year}-${month.padStart(2, '0')}-01`;
  const lastDay = new Date(Number(year), Number(month), 0).getDate();
  const toDate = `${year}-${month.padStart(2, '0')}-${lastDay}`;

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from) => {
          if (!from) return;
          const [y, m] = from.split('-');
          if (y && m) {
            setYear(y);
            setMonth(String(Number(m)));
            setPage(1);
          }
        }}
        dateLabel={L.list.filterMonth}
        onSearch={handleLoad}
        searchAriaLabel="Tìm"
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select
                label={L.list.filterMonth}
                value={month}
                onChange={e => {
                  setMonth(e.target.value);
                  setPage(1);
                }}
                options={MONTH_OPTIONS}
                fullWidth
                data-testid={`${TEST_ID}-month`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select
                label={L.list.filterYear}
                value={year}
                onChange={e => {
                  setYear(e.target.value);
                  setPage(1);
                }}
                options={yearOptions()}
                fullWidth
                data-testid={`${TEST_ID}-year`}
              />
            </div>
            <div data-testid={`${TEST_ID}-field-processing-level`}>
              <Select
                label={L.list.filterProcessingLevel}
                value={processingLevel}
                onChange={e => {
                  setProcessingLevel(e.target.value);
                  setPage(1);
                }}
                options={PROCESSING_LEVEL_OPTIONS}
                fullWidth
                data-testid={`${TEST_ID}-processing-level`}
              />
            </div>
          </>
        )}
      />
    ),
    [fromDate, toDate, month, year, processingLevel, handleLoad, showTableLoading],
  );

  const wipSummary = (
    <div className={erp.summaryBar} data-testid={`${TEST_ID}-wip-summary`}>
      <div className={erp.summaryItem}>
        <label className={erp.label}>{L.list.wipOpening}</label>
        <strong>{formatVnd(wipOpening)}</strong>
      </div>
      <div className={erp.summaryItem}>
        <label className={erp.label}>{L.list.wipClosing}</label>
        <strong>{formatVnd(wipClosing)}</strong>
      </div>
      <div className={erp.summaryItem}>
        <label className={erp.label}>{L.list.wipOrderCount}</label>
        <strong>{wipRows.length}</strong>
      </div>
    </div>
  );

  const listBody =
    !showTableLoading && items.length === 0 ? (
      <>
        {wipSummary}
        <div className={erp.empty}>{L.list.empty}</div>
      </>
    ) : !showTableLoading ? (
      <>
        {wipSummary}
        <div className={erp.tableWrapper}>
          <table className={erp.table}>
            <thead>
              <tr>
                <th>{L.list.colCode}</th>
                <th>{L.list.colProduct}</th>
                <th className={erp.colRight}>{L.detail.actualQty}</th>
                <th className={erp.colRight}>{L.list.colTotal}</th>
                <th className={erp.colRight}>{L.list.colUnitCost}</th>
                <th>{L.list.colProcessingLevel}</th>
              </tr>
            </thead>
            <tbody>
              {items.map(r => (
                <tr key={r.id} data-testid={`${TEST_ID}-row-${r.id}`}>
                  <td>
                    <button
                      type="button"
                      className={erp.codeLink}
                      onClick={() => navigate(`/gt/gia-thanh/${r.id}`)}
                    >
                      <code>{r.code}</code>
                    </button>
                  </td>
                  <td>{r.productName ?? r.productCode}</td>
                  <td className={erp.colRight}>{r.actualQty}</td>
                  <td className={erp.colRight}>{formatVnd(r.totalCost)}</td>
                  <td className={erp.colRight}>{formatVnd(r.unitCost)}</td>
                  <td>
                    <DocumentProcessingLevelPill
                      label={formatCostSheetProcessingLevel(r.processingLevel)}
                      compact
                      testId={`${TEST_ID}-level-${r.id}`}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: L.list.title,
          titleIconClass: 'fas fa-industry',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={L.list.listTitle}
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={
          totalCount > 0 ? (
            <VoucherListPagination
              testIdPrefix={TEST_ID}
              page={page}
              totalCount={totalCount}
              pageSize={pageSize}
              onPageChange={setPage}
              onPageSizeChange={size => {
                setPageSize(size as ListPageSize);
                setPage(1);
              }}
            />
          ) : undefined
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default GiaThanhListPage;
